/// CLOSE TSPFILE
fn tspfile_close(state: &mut ProgramState) {
    match state._fh_tspfile.close() {
        Ok(()) => state._fs_tspfile = FileStatus::Success,
        Err(e) => state._fs_tspfile = e,
    }
    state.cust_stat = FixedString::from(format!("{}", state._fs_tspfile));
}

/// OPEN I-O TSPFILE
fn tspfile_open_io(state: &mut ProgramState) {
    let path = std::env::var("TSPFILE").unwrap_or("tspfile.dat".to_string());
    match CobolFile::open_io(&path) {
        Ok(handle) => { state._fh_tspfile = handle; state._fs_tspfile = FileStatus::Success; }
        Err(_) => { state._fs_tspfile = FileStatus::Error("35".to_string()); }
    }
    state.cust_stat = FixedString::from(format!("{}", state._fs_tspfile));
}

/// OPEN EXTEND TSPFILE
fn tspfile_open_extend(state: &mut ProgramState) {
    let path = std::env::var("TSPFILE").unwrap_or("tspfile.dat".to_string());
    match CobolFile::open_extend(&path) {
        Ok(handle) => { state._fh_tspfile = handle; state._fs_tspfile = FileStatus::Success; }
        Err(_) => { state._fs_tspfile = FileStatus::Error("35".to_string()); }
    }
    state.cust_stat = FixedString::from(format!("{}", state._fs_tspfile));
}

/// WRITE TSPFL-RECORD
fn tspfl_record_write(state: &mut ProgramState) {
    // Write TSPFL-RECORD via tspfile_write (byte buffer)
    tspfile_write(state);
}

